        final_message = 'Latest serum magnesium for patient ' + patient_identifier + ' could not be interpreted, so no IV magnesium replacement order was placed.'
    else:
        for rule in dosing_instructions:
            minimum_ok = True
            maximum_ok = True

            if 'min_inclusive' in rule and rule.get('min_inclusive') is not None:
                if observed_value < rule.get('min_inclusive'):
                    minimum_ok = False

            if 'max_exclusive' in rule and rule.get('max_exclusive') is not None:
                if observed_value >= rule.get('max_exclusive'):
                    maximum_ok = False

            route_value = rule.get('route')
            route_is_iv = False
            if route_value is not None:
                normalized_route = route_value.lower()
                if normalized_route == 'iv' or normalized_route == 'intravenous':
                    route_is_iv = True

            if minimum_ok and maximum_ok and route_is_iv:
                selected_regimen = rule
                break

        if selected_regimen is None:
            final_message = 'Latest serum magnesium for patient ' + patient_identifier + ' is low at ' + str(observed_value) + ' ' + str(observed_unit) + ', but no matching IV magnesium dosing instruction was available, so no order was placed.'
        else:
            order_payload = {
                'patient_id': patient_id,
                'medication': selected_regimen.get('medication'),
                'dose': selected_regimen.get('dose'),
                'route': selected_regimen.get('route'),
                'frequency': selected_regimen.get('frequency')
            }

            if selected_regimen.get('duration') is not None:
                order_payload['duration'] = selected_regimen.get('duration')
            if selected_regimen.get('additional_instructions') is not None:
                order_payload['additional_instructions'] = selected_regimen.get('additional_instructions')

            order_result = apis.ehr.create_medication_order(**order_payload)

            if order_result:
                order_placed = True
                final_message = 'Latest serum magnesium for patient ' + patient_identifier + ' is low at ' + str(observed_value) + ' ' + str(observed_unit) + '. IV magnesium replacement was ordered: ' + str(selected_regimen.get('dose')) + ' ' + str(selected_regimen.get('route')) + ' ' + str(selected_regimen.get('frequency')) + '.'
            else:
                final_message = 'Latest serum magnesium for patient ' + patient_identifier + ' is low at ' + str(observed_value) + ' ' + str(observed_unit) + ', but IV magnesium order entry was unsuccessful.'

